// Rust implementation should follow semantic specification
// Use Rust idioms while maintaining mathematical equivalence

use std::collections::HashMap;

pub struct EmpiricalHRF {
    t_points: Vec<f64>,
    y_values: Vec<f64>,
    span: f64,
    nbasis: usize,
}

impl EmpiricalHRF {
    pub fn new(t_points: Vec<f64>, y_values: Vec<f64>) -> Self {
        let span = t_points.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
        EmpiricalHRF {
            t_points,
            y_values,
            span,
            nbasis: 1,
        }
    }

    pub fn evaluate(&self, t: f64) -> f64 {
        // Handle boundary cases
        if t < self.t_points[0] || t > self.t_points[self.t_points.len() - 1] {
            return 0.0;
        }

        // Find interpolation interval
        for i in 0..self.t_points.len() - 1 {
            if t >= self.t_points[i] && t <= self.t_points[i + 1] {
                // Linear interpolation
                let t1 = self.t_points[i];
                let t2 = self.t_points[i + 1];
                let y1 = self.y_values[i];
                let y2 = self.y_values[i + 1];

                return y1 + (y2 - y1) * (t - t1) / (t2 - t1);
            }
        }

        // Exact match (shouldn't reach here with proper input)
        for (i, &t_point) in self.t_points.iter().enumerate() {
            if (t - t_point).abs() < f64::EPSILON {
                return self.y_values[i];
            }
        }

        0.0
    }

    pub fn nbasis(&self) -> usize {
        self.nbasis
    }

    pub fn span(&self) -> f64 {
        self.span
    }
}

pub fn empirical_hrf(t_points: &[f64], y_values: &[f64]) -> EmpiricalHRF {
    EmpiricalHRF::new(t_points.to_vec(), y_values.to_vec())
}
